unit lipdecide;

{$mode objfpc}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

function RoundToSignificant(const V: real; const Digits: integer): real;
var
  AbsV, Scale, P: real;
  Exp10: integer;
begin
  if V = 0.0 then
    exit(0.0);

  AbsV := Abs(V);
  Exp10 := Floor(Log10(AbsV));
  P := Digits - 1 - Exp10;
  Scale := Power(10.0, P);

  if V > 0.0 then
    Result := Int(V * Scale + 0.5) / Scale
  else
    Result := -Int((-V) * Scale + 0.5) / Scale;
end;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  RA, RB: real;
begin
  RA := RoundToSignificant(A, 6);
  RB := RoundToSignificant(B, 6);

  if RA < RB then
    Result := LT
  else if RA > RB then
    Result := GT
  else
    Result := EQ;
end;

function RLT(const A, B: real): boolean; inline;
begin
  Result := REALCOMPARE(A, B) = LT;
end;

function REQ(const A, B: real): boolean; inline;
begin
  Result := REALCOMPARE(A, B) = EQ;
end;

function RGT(const A, B: real): boolean; inline;
begin
  Result := REALCOMPARE(A, B) = GT;
end;

function Distance(const I, J: integer): real;
var
  DX, DY: real;
begin
  DX := X[J] - X[I];
  DY := Y[J] - Y[I];
  Result := Sqrt(DX * DX + DY * DY);
end;

function SamePoint(const I, J: integer): boolean;
begin
  Result := REQ(X[I], X[J]) and REQ(Y[I], Y[J]);
end;

function TriangleArea(const I, J, K: integer): real;
var
  Cross: real;
begin
  Cross := (X[J] - X[I]) * (Y[K] - Y[I]) - (X[K] - X[I]) * (Y[J] - Y[I]);
  Result := Abs(Cross) / 2.0;
end;

procedure Sort3(var A, B, C: real);
var
  T: real;
begin
  if RGT(A, B) then
  begin
    T := A;
    A := B;
    B := T;
  end;

  if RGT(B, C) then
  begin
    T := B;
    B := C;
    C := T;
  end;

  if RGT(A, B) then
  begin
    T := A;
    A := B;
    B := T;
  end;
end;

function CannotFitInCircle(const I, J, K: integer; const R: real): boolean;
var
  A, B, C, Area2, CircumR: real;
  S1, S2, S3: real;
begin
  A := Distance(I, J);
  B := Distance(J, K);
  C := Distance(I, K);

  S1 := A;
  S2 := B;
  S3 := C;
  Sort3(S1, S2, S3);

  if RGT(S3, 2.0 * R) then
    exit(true);

  if REALCOMPARE(S3 * S3, S1 * S1 + S2 * S2) <> LT then
    exit(false);

  Area2 := Abs((X[J] - X[I]) * (Y[K] - Y[I]) - (X[K] - X[I]) * (Y[J] - Y[I]));
  if REQ(Area2, 0.0) then
    exit(false);

  CircumR := (S1 * S2 * S3) / (2.0 * Area2);
  Result := RGT(CircumR, R);
end;

function PointLineDistance(const P, A, B: integer): real;
var
  DX, DY, Num, Den: real;
begin
  if SamePoint(A, B) then
    exit(Distance(P, A));

  DX := X[B] - X[A];
  DY := Y[B] - Y[A];
  Num := Abs(DY * X[P] - DX * Y[P] + X[B] * Y[A] - Y[B] * X[A]);
  Den := Sqrt(DX * DX + DY * DY);
  Result := Num / Den;
end;

function AngleCondition(const I, J, K: integer; const Eps: real): boolean;
var
  VX1, VY1, VX2, VY2, DotP, Mag1, Mag2, CosV, Ang: real;
begin
  if SamePoint(I, J) or SamePoint(K, J) then
    exit(false);

  VX1 := X[I] - X[J];
  VY1 := Y[I] - Y[J];
  VX2 := X[K] - X[J];
  VY2 := Y[K] - Y[J];

  DotP := VX1 * VX2 + VY1 * VY2;
  Mag1 := Sqrt(VX1 * VX1 + VY1 * VY1);
  Mag2 := Sqrt(VX2 * VX2 + VY2 * VY2);

  CosV := DotP / (Mag1 * Mag2);
  if RGT(CosV, 1.0) then
    CosV := 1.0
  else if RLT(CosV, -1.0) then
    CosV := -1.0;

  Ang := ArcCos(CosV);
  Result := RLT(Ang, PI - Eps) or RGT(Ang, PI + Eps);
end;

function PointQuadrant(const PX, PY: real): integer;
begin
  if (not RLT(PX, 0.0)) and (not RLT(PY, 0.0)) then
    exit(1);

  if RLT(PX, 0.0) and (not RLT(PY, 0.0)) then
    exit(2);

  if RLT(PY, 0.0) and (not RGT(PX, 0.0)) then
    exit(3);

  Result := 4;
end;

function LIC1: boolean;
var
  I: integer;
begin
  Result := false;
  for I := 1 to NUMPOINTS - 1 do
    if RGT(Distance(I, I + 1), PARAMETERS.LENGTH1) then
      exit(true);
end;

function LIC2: boolean;
var
  I: integer;
begin
  Result := false;
  for I := 1 to NUMPOINTS - 2 do
    if CannotFitInCircle(I, I + 1, I + 2, PARAMETERS.RADIUS1) then
      exit(true);
end;

function LIC3: boolean;
var
  I: integer;
begin
  Result := false;
  for I := 1 to NUMPOINTS - 2 do
    if AngleCondition(I, I + 1, I + 2, PARAMETERS.EPSILON) then
      exit(true);
end;

function LIC4: boolean;
var
  I: integer;
begin
  Result := false;
  for I := 1 to NUMPOINTS - 2 do
    if RGT(TriangleArea(I, I + 1, I + 2), PARAMETERS.AREA1) then
      exit(true);
end;

function LIC5: boolean;
var
  StartIdx, I, Q, Count: integer;
  Seen: array[1..4] of boolean;
begin
  Result := false;
  for StartIdx := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    Seen[1] := false;
    Seen[2] := false;
    Seen[3] := false;
    Seen[4] := false;
    Count := 0;

    for I := StartIdx to StartIdx + PARAMETERS.Q_PTS - 1 do
    begin
      Q := PointQuadrant(X[I], Y[I]);
      if not Seen[Q] then
      begin
        Seen[Q] := true;
        Inc(Count);
      end;
    end;

    if Count > PARAMETERS.QUADS then
      exit(true);
  end;
end;

function LIC6: boolean;
var
  I: integer;
begin
  Result := false;
  for I := 1 to NUMPOINTS - 1 do
    if RLT(X[I + 1] - X[I], 0.0) then
      exit(true);
end;

function LIC7: boolean;
var
  StartIdx, EndIdx, Mid: integer;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit(false);

  for StartIdx := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    EndIdx := StartIdx + PARAMETERS.N_PTS - 1;
    for Mid := StartIdx + 1 to EndIdx - 1 do
      if RGT(PointLineDistance(Mid, StartIdx, EndIdx), PARAMETERS.DIST) then
        exit(true);
  end;
end;

function LIC8: boolean;
var
  I, J: integer;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit(false);

  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    if RGT(Distance(I, J), PARAMETERS.LENGTH1) then
      exit(true);
  end;
end;

function LIC9: boolean;
var
  I, J, K: integer;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit(false);

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;
    if CannotFitInCircle(I, J, K, PARAMETERS.RADIUS1) then
      exit(true);
  end;
end;

function LIC10: boolean;
var
  I, J, K: integer;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit(false);

  for I := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    J := I + PARAMETERS.C_PTS + 1;
    K := J + PARAMETERS.D_PTS + 1;
    if AngleCondition(I, J, K, PARAMETERS.EPSILON) then
      exit(true);
  end;
end;

function LIC11: boolean;
var
  I, J, K: integer;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit(false);

  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;
    if RGT(TriangleArea(I, J, K), PARAMETERS.AREA1) then
      exit(true);
  end;
end;

function LIC12: boolean;
var
  I, J: integer;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit(false);

  for I := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    J := I + PARAMETERS.G_PTS + 1;
    if RLT(X[J] - X[I], 0.0) then
      exit(true);
  end;
end;

function LIC13: boolean;
var
  I, J: integer;
  HasLong, HasShort: boolean;
begin
  Result := false;
  if NUMPOINTS < 3 then
    exit(false);

  HasLong := false;
  HasShort := false;

  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    if RGT(Distance(I, J), PARAMETERS.LENGTH1) then
      HasLong := true;
    if RLT(Distance(I, J), PARAMETERS.LENGTH2) then
      HasShort := true;
  end;

  Result := HasLong and HasShort;
end;

function LIC14: boolean;
var
  I, J, K: integer;
  HasOutsideR1, HasInsideR2: boolean;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit(false);

  HasOutsideR1 := false;
  HasInsideR2 := false;

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;

    if CannotFitInCircle(I, J, K, PARAMETERS.RADIUS1) then
      HasOutsideR1 := true;
    if not CannotFitInCircle(I, J, K, PARAMETERS.RADIUS2) then
      HasInsideR2 := true;
  end;

  Result := HasOutsideR1 and HasInsideR2;
end;

function LIC15: boolean;
var
  I, J, K: integer;
  HasBigArea, HasSmallArea: boolean;
  Area: real;
begin
  Result := false;
  if NUMPOINTS < 5 then
    exit(false);

  HasBigArea := false;
  HasSmallArea := false;

  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;

    Area := TriangleArea(I, J, K);
    if RGT(Area, PARAMETERS.AREA1) then
      HasBigArea := true;
    if RLT(Area, PARAMETERS.AREA2) then
      HasSmallArea := true;
  end;

  Result := HasBigArea and HasSmallArea;
end;

procedure DECIDE;
var
  I, J: integer;
  RowAllTrue: boolean;
begin
  CMV[1] := LIC1;
  CMV[2] := LIC2;
  CMV[3] := LIC3;
  CMV[4] := LIC4;
  CMV[5] := LIC5;
  CMV[6] := LIC6;
  CMV[7] := LIC7;
  CMV[8] := LIC8;
  CMV[9] := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;

  for I := 1 to 15 do
    for J := 1 to 15 do
      if I <> J then
        case LCM[I, J] of
          NOTUSED: PUM[I, J] := true;
          ANDD: PUM[I, J] := CMV[I] and CMV[J];
          ORR: PUM[I, J] := CMV[I] or CMV[J];
        end;

  for I := 1 to 15 do
  begin
    if not PUM[I, I] then
      FUV[I] := true
    else
    begin
      RowAllTrue := true;
      for J := 1 to 15 do
        if not PUM[I, J] then
        begin
          RowAllTrue := false;
          Break;
        end;
      FUV[I] := RowAllTrue;
    end;
  end;

  LAUNCH := true;
  for I := 1 to 15 do
    if not FUV[I] then
    begin
      LAUNCH := false;
      Break;
    end;
end;

end.
